
public class IncreaseDecreaseValueByOne {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int bottleCount = 0;
		
		bottleCount = bottleCount+1;
		
		bottleCount/=1; //Assignment operator +=
		
		System.out.println(bottleCount);
		
		bottleCount++; //Increment Operator ++ Decrement Operator --
		
		System.out.println(bottleCount);
		
		bottleCount--;
		
		System.out.println(bottleCount);
		
		bottleCount-=1;
		
	}

}
